function codeTestRunner(patch, testCases) {
  const results = testCases.map(tc => {
    const missing  = (tc.must_contain     || []).filter(s => !patch.includes(s));
    const forbid   = (tc.must_not_contain || []).filter(s =>  patch.includes(s));
    const regexOk  = tc.must_match ? new RegExp(tc.must_match, 'm').test(patch) : true;
    const pass = missing.length === 0 && forbid.length === 0 && regexOk;
    return { name: tc.name, pass, missing, forbid, regexOk };
  });
  return {
    pass: results.every(r => r.pass),
    passedCount: results.filter(r => r.pass).length,
    totalCount: results.length,
    details: results
  };
}

